create table my_user
(
    id                  varchar(36)                 not null
        primary key,
    username            varchar(150)                not null
        unique,
    email               varchar(254)  default NULL::character varying,
    phone               varchar(14)   default NULL::character varying,
    nickname            varchar(128)  default NULL::character varying,
    avatar              varchar(4096) default NULL::character varying,
    first_name          varchar(150),
    last_name           varchar(150),
    password            varchar(128),
    is_superuser        boolean       default false not null,
    is_staff            boolean       default false not null,
    is_active           boolean       default true  not null,
    last_login          timestamp with time zone,
    updated_at          timestamp with time zone,
    date_joined         timestamp with time zone,
    description         text,
    register_source     jsonb         default 'null'::jsonb,
    inviter_id          varchar(36),
    extension           jsonb         default 'null'::jsonb,
    api_key             varchar(255)  default ''::character varying,
    wechat_avatar       varchar(4096),
    wechat_openid       varchar(128)
        unique,
    wechat_unionid      varchar(128)
        unique,
    user_id             integer,
    organization_id     integer,
    github_avatar       varchar(4096),
    github_email        varchar(254),
    github_id           varchar(64)
        unique,
    github_login        varchar(128),
    is_virtual_api_user boolean                     not null
);

alter table my_user
    owner to myscale_kb_backend;

create index idx_user_virtual_api
    on my_user (is_virtual_api_user, username)
    where (is_virtual_api_user = true);

create index my_user_github_id_f6a34116_like
    on my_user (github_id varchar_pattern_ops);

create index my_user_id_9c27653a_like
    on my_user (id varchar_pattern_ops);

create index my_user_inviter_id_2fb618f6
    on my_user (inviter_id);

create index my_user_inviter_id_2fb618f6_like
    on my_user (inviter_id varchar_pattern_ops);

create index my_user_username_131111b6_like
    on my_user (username varchar_pattern_ops);

create index my_user_wechat_openid_d01bfe6a_like
    on my_user (wechat_openid varchar_pattern_ops);

create index my_user_wechat_unionid_c4d077f6_like
    on my_user (wechat_unionid varchar_pattern_ops);

